// Demonstrates N-API trampolines generated by rosetta.
//
// `Shape` is an abstract C++ class (pure virtual `area`, virtual `describe`).
// Because the generated bindings use a Js_Shape trampoline, JS subclasses can
// override those virtuals and C++ dispatches back into JS.
//
// Run after building:  node test_shapes.js

const { Shape } = require('./shapes.node');

class Circle extends Shape {
    constructor(r) { super(); this.r = r; this.label = 'circle'; }
    area() { return Math.PI * this.r * this.r; }   // overrides the pure virtual
    describe() { return `circle r=${this.r}`; }     // overrides the virtual+default
}

class Square extends Shape {
    constructor(s) { super(); this.s = s; }
    area() { return this.s * this.s; }              // overrides the pure virtual
    // describe() NOT overridden -> falls back to the C++ Shape::describe() body
}

const c = new Circle(2);
console.assert(Math.abs(c.area() - Math.PI * 4) < 1e-9, 'circle area');
console.assert(c.describe() === 'circle r=2', 'circle describe: ' + c.describe());

const s = new Square(3);
console.assert(Math.abs(s.area() - 9) < 1e-9, 'square area');
// Recursion guard: describe() not overridden -> C++ base returns label "shape".
console.assert(s.describe() === 'shape', 'square describe fallback: ' + s.describe());

// C++ -> JS dispatch: scaled_area is a NON-virtual C++ method that calls the
// virtual area() internally; on a JS subclass it must reach the JS override.
console.assert(Math.abs(c.scaled_area(10) - 10 * Math.PI * 4) < 1e-9,
    'C++ -> JS via scaled_area: ' + c.scaled_area(10));
console.assert(Math.abs(s.scaled_area(2) - 18) < 1e-9,
    'C++ -> JS (square): ' + s.scaled_area(2));

// Calling a pure virtual with no JS override must throw.
let threw = false;
try { new Shape().area(); } catch (e) { threw = true; }
console.assert(threw, 'un-overridden pure virtual should throw');

console.log('trampoline OK: JS overrides dispatched through C++ virtuals');
